const fs = require('fs');
const lines = fs.readFileSync('tests/fixtures/real-cdr-samples.ndjson', 'utf8').split('\n').filter(Boolean);
const QUEUES = new Set(['8020','8021','8030','8031']);
const TRACKED = new Set(['6135949199']);
function normalize(s) {
  if (!s) return null;
  const digits = s.replace(/\D/g, '');
  if (digits.length === 11 && digits.startsWith('1')) return digits.slice(1);
  if (digits.length === 10) return digits;
  return null;
}
const byCall = {};
for (const l of lines) {
  const r = JSON.parse(l);
  const cid = r.from.call_id;
  const dnisHit = TRACKED.has(normalize(r.to?.id));
  const queueHit = QUEUES.has(r.to?.user);
  if (!byCall[cid]) byCall[cid] = { dnis: false, queue: false };
  byCall[cid].dnis = byCall[cid].dnis || dnisHit;
  byCall[cid].queue = byCall[cid].queue || queueHit;
}
let dnisOnly = 0, both = 0, queueOnly = 0, neither = 0;
for (const v of Object.values(byCall)) {
  if (v.dnis && v.queue) both++;
  else if (v.dnis) dnisOnly++;
  else if (v.queue) queueOnly++;
  else neither++;
}
console.log({ totalCalls: Object.keys(byCall).length, dnisMatch: dnisOnly+both, queueOnly, neither, currentInclusion: dnisOnly+both+queueOnly, dnisOnlyInclusion: dnisOnly+both });
"

